const results = $input.first().json.results || [];

const posts = results.map(page => {
  const props = page.properties;
  const getText = p => p?.rich_text?.[0]?.plain_text || p?.title?.[0]?.plain_text || '';
  const getSelect = p => p?.select?.name || '';
  const getDate = p => p?.date?.start || '';
  const getNum = p => p?.number || 0;
  return {
    page_id: page.id,
    titel: getText(props['Titel']),
    typ: getText(props['Type']),
    saeule: getSelect(props['Säule']),
    geplant_fuer: getDate(props['Geplant für']),
    kw: getNum(props['KW']),
    hook: getText(props['Hook']),
    kern_inhalt: getText(props['Kern-Inhalt']),
    cta: getText(props['CTA']),
    hashtags: getText(props['Hashtags'])
  };
});

console.log(`📝 ${posts.length} Posts ohne LinkedIn-Text gefunden – starte Textgenerierung`);
posts.forEach((p, i) => console.log(`  ${i+1}. "${p.titel}" (${p.geplant_fuer})`));

return posts.map(p => ({ json: p }));

const claudeResponse = $input.first().json;
const rawText = claudeResponse.content?.[0]?.text || '';

if (!rawText) {
  const errMsg = claudeResponse.error?.message || JSON.stringify(claudeResponse).substring(0, 200);
  throw new Error(`Kein Text von Claude: ${errMsg}`);
}

// page_id aus dem ursprünglichen Batch-Item holen
const originalPost = $('Posts einzeln verarbeiten').first().json;
const pageId = originalPost.page_id;
const titel = originalPost.titel;

let postText = '';
try {
  const parsed = JSON.parse(rawText);
  postText = parsed.post_text || '';
} catch(e) {
  // JSON-Block aus Markdown extrahieren falls vorhanden
  const m = rawText.match(/```json\s*([\s\S]*?)\s*```/);
  if (m) {
    try { postText = JSON.parse(m[1]).post_text || ''; } catch(e2) {}
  }
  // Letzter Versuch: direkt nach post_text suchen
  if (!postText) {
    const m2 = rawText.match(/"post_text"\s*:\s*"([\s\S]*?)"\s*}/);
    postText = m2 ? m2[1].replace(/\\n/g, '\n').replace(/\\t/g, '\t') : rawText.trim();
  }
}

if (!postText || postText.length < 50) {
  throw new Error(`Post-Text für "${titel}" zu kurz oder leer (${postText.length} Zeichen).`);
}

console.log(`✅ Post-Text generiert: "${titel}" – ${postText.length} Zeichen | page_id: ${pageId}`);

return [{
  json: {
    page_id: pageId,
    titel: titel,
    post_text: postText
  }
}];

const items = $('Posts aufbereiten').all();
const anzahl = items.length;
console.log(`✅ Post-Text-Generator abgeschlossen: ${anzahl} Posts verarbeitet`);
return [{
  json: {
    status: 'Abgeschlossen',
    anzahl_posts: anzahl,
    zeitstempel: new Date().toISOString(),
    hinweis: `${anzahl} Posts wurden mit Claude-generiertem Post-Text in der Content Pipeline aktualisiert.`
  }
}];
